def extract_batch(documents: list[str]) -> list[Invoice]:
    results = []

    for i, doc in enumerate(documents):
        try:
            raw_result = optimized_extractor(doc)
            invoice = Invoice(**{
                'name': raw_result.name,
                'amount': float(raw_result.amount),
                'date': raw_result.date,
                'invoice_id': raw_result.invoice_id
            })
            results.append(invoice)
            print(f"✓ Document {i+1}: {invoice.invoice_id}")
        except Exception as e:
            print(f"✗ Document {i+1} failed: {e}")

    return results

# Usage
invoices = extract_batch([
    "Invoice #INV-123 to Acme Corp $1250 2024-03-15",
    "Invoice INV-456 Beta Ltd $2300.50 2024-04-01"
])

