from typing import Dict, Any

@vex.verify(
    assertions=[
        "all(key in result for key in ['name', 'amount', 'date', 'invoice_id'])",
        "isinstance(result['amount'], (int, float)) and result['amount'] > 0",
        "bool(re.match(r'^\\d{4}-\\d{2}-\\d{2}$', result['date']))",
        vex.schema_compliance('Invoice')
    ],
    fallback='reject'
)
def complete_extractor(document: str) -> Dict[str, Any]:
    raw = optimized_extractor(document)
    return dict(raw.__dict__)

# Production usage
safe_results = [complete_extractor(doc) for doc in documents]
